const canvas = document.createElement("canvas");
const ctx = canvas.getContext("2d");
document.body.style.margin = "0";
document.body.style.overflow = "hidden";
document.body.appendChild(canvas);

let W = window.innerWidth;
let H = window.innerHeight;
canvas.width = W;
canvas.height = H;

window.addEventListener("resize", () => {
  W = window.innerWidth;
  H = window.innerHeight;
  canvas.width = W;
  canvas.height = H;
});

const keys = Object.create(null);
window.addEventListener("keydown", (e) => {
  keys[e.key.toLowerCase()] = true;
  if (["arrowup", "arrowdown", "arrowleft", "arrowright", " "].includes(e.key.toLowerCase())) e.preventDefault();
});
window.addEventListener("keyup", (e) => {
  keys[e.key.toLowerCase()] = false;
});

const player = {
  x: 100,
  y: 100,
  angle: 0,
  speed: 0,
  maxSpeed: 420,
  accel: 520,
  brake: 720,
  friction: 300,
  turnSpeed: 3.2,
  radius: 16
};

const track = {
  x: 0,
  y: 0,
  width: 2600,
  height: 1800,
  lane: 180
};

const checkpoints = [
  { x: 400, y: 300 },
  { x: 2200, y: 300 },
  { x: 2200, y: 1500 },
  { x: 400, y: 1500 }
];

let distanceTraveled = 0;
let lap = 0;
let targetCheckpoint = 0;
let lastFrame = performance.now();
let raceStart = performance.now();

function clamp(v, min, max) {
  return Math.max(min, Math.min(max, v));
}

function wrapAngle(a) {
  while (a > Math.PI) a -= Math.PI * 2;
  while (a < -Math.PI) a += Math.PI * 2;
  return a;
}

function update(dtMs) {
  const dt = dtMs / 1000;

  if (keys["arrowup"] || keys["w"]) {
    player.speed += player.accel * dt;
  } else if (keys["arrowdown"] || keys["s"]) {
    player.speed -= player.brake * dt;
  } else {
    const sign = Math.sign(player.speed);
    const mag = Math.max(0, Math.abs(player.speed) - player.friction * dt);
    player.speed = mag * sign;
  }

  player.speed = clamp(player.speed, -player.maxSpeed * 0.5, player.maxSpeed);

  const steering = (keys["arrowleft"] || keys["a"] ? -1 : 0) + (keys["arrowright"] || keys["d"] ? 1 : 0);
  const turnFactor = 0.35 + 0.65 * (Math.min(1, Math.abs(player.speed) / player.maxSpeed));
  player.angle += steering * player.turnSpeed * turnFactor * dt * (player.speed >= 0 ? 1 : -1);
  player.angle = wrapAngle(player.angle);

  const prevX = player.x;
  const prevY = player.y;

  player.x += Math.cos(player.angle) * player.speed * dt;
  player.y += Math.sin(player.angle) * player.speed * dt;

  if (player.x < track.x + player.radius) {
    player.x = track.x + player.radius;
    player.speed *= -0.25;
  }
  if (player.y < track.y + player.radius) {
    player.y = track.y + player.radius;
    player.speed *= -0.25;
  }
  if (player.x > track.x + track.width - player.radius) {
    player.x = track.x + track.width - player.radius;
    player.speed *= -0.25;
  }
  if (player.y > track.y + track.height - player.radius) {
    player.y = track.y + track.height - player.radius;
    player.speed *= -0.25;
  }

  const dx = player.x - prevX;
  const dy = player.y - prevY;
  distanceTraveled += Math.hypot(dx, dy);

  const cp = checkpoints[targetCheckpoint];
  const dcp = Math.hypot(player.x - cp.x, player.y - cp.y);
  if (dcp < 80) {
    targetCheckpoint++;
    if (targetCheckpoint >= checkpoints.length) {
      targetCheckpoint = 0;
      lap++;
    }
  }
}

function drawTrack() {
  ctx.fillStyle = "#1b5e20";
  ctx.fillRect(0, 0, W, H);

  const offsetX = W / 2 - player.x;
  const offsetY = H / 2 - player.y;

  ctx.save();
  ctx.translate(offsetX, offsetY);

  ctx.fillStyle = "#7b5b3a";
  ctx.fillRect(track.x, track.y, track.width, track.height);

  ctx.fillStyle = "#c9c9c9";
  ctx.fillRect(track.x + track.lane, track.y + track.lane, track.width - track.lane * 2, track.height - track.lane * 2);

  ctx.strokeStyle = "#ffffff";
  ctx.lineWidth = 6;
  ctx.setLineDash([30, 20]);
  ctx.beginPath();
  ctx.rect(track.x + track.lane / 2, track.y + track.lane / 2, track.width - track.lane, track.height - track.lane);
  ctx.stroke();
  ctx.setLineDash([]);

  for (let i = 0; i < checkpoints.length; i++) {
    const c = checkpoints[i];
    ctx.fillStyle = i === targetCheckpoint ? "#ffeb3b" : "#03a9f4";
    ctx.beginPath();
    ctx.arc(c.x, c.y, 16, 0, Math.PI * 2);
    ctx.fill();
  }

  ctx.fillStyle = "#000";
  ctx.beginPath();
  ctx.arc(player.x, player.y, player.radius + 4, 0, Math.PI * 2);
  ctx.fill();

  ctx.save();
  ctx.translate(player.x, player.y);
  ctx.rotate(player.angle);
  ctx.fillStyle = "#ff1744";
  ctx.beginPath();
  ctx.moveTo(20, 0);
  ctx.lineTo(-14, -10);
  ctx.lineTo(-10, 0);
  ctx.lineTo(-14, 10);
  ctx.closePath();
  ctx.fill();
  ctx.restore();

  ctx.restore();
}

function drawHUD() {
  const elapsed = (performance.now() - raceStart) / 1000;
  ctx.fillStyle = "rgba(0,0,0,0.5)";
  ctx.fillRect(12, 12, 320, 110);

  ctx.fillStyle = "#fff";
  ctx.font = "18px sans-serif";
  ctx.fillText("Arrow keys / WASD to drive", 24, 38);
  ctx.fillText("Distance: " + distanceTraveled.toFixed(1) + " px", 24, 64);
  ctx.fillText("Lap: " + lap, 24, 90);
  ctx.fillText("Time: " + elapsed.toFixed(1) + " s", 24, 116);
}

function frame(now) {
  const dt = now - lastFrame;
  lastFrame = now;
  update(dt);
  drawTrack();
  drawHUD();
}

setInterval(() => {
  frame(performance.now());
}, 16);